import json
import os

class CachingApi:
    def __init__(self, cache_dir):
        self.cache_dir = cache_dir

    def get_cached_response(self, api_endpoint, request_params):
        cache_file_path = os.path.join(self.cache_dir, f"{api_endpoint}-{json.dumps(request_params)}.json")

        if os.path.exists(cache_file_path):
            with open(cache_file_path, "r") as f:
                return json.load(f)

    def cache_response(self, api_endpoint, request_params, response):
        cache_file_path = os.path.join(self.cache_dir, f"{api_endpoint}-{json.dumps(request_params)}.json")

        os.makedirs(os.path.dirname(cache_file_path), exist_ok=True)
        with open(cache_file_path, "w") as f:
            json.dump(response, f)

        return response